   1→//! Specification-level diffing: compare two [`FunctionSpec`]s to detect
   2→//! behavioral regressions, added/removed equivalence classes, and changed
   3→//! pre/postconditions.
   4→//!
   5→//! The main entry point is [`diff_specs`], which produces a [`SpecDiff`].
   6→//! Two formatters are provided: [`format_spec_diff_text`] for human-readable
   7→//! output and [`format_spec_diff_json`] for machine-readable JSON.
   8→
   9→use serde::{Deserialize, Serialize};
  10→
  11→use crate::equivalence::Precondition;
  12→use crate::nondeterminism::NondeterministicField;
  13→use crate::spec::{FunctionSpec, Postcondition, SpecClass};
  14→
  15→/// The result of diffing two function specifications.
  16→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
  17→pub struct SpecDiff {
  18→    /// Function name being compared.
  19→    pub function_name: String,
  20→    /// Equivalence classes present in the new spec but not the old.
  21→    pub added_classes: Vec<SpecClass>,
  22→    /// Equivalence classes present in the old spec but not the new.
  23→    pub removed_classes: Vec<SpecClass>,
  24→    /// Postconditions that changed between matching classes.
  25→    pub changed_postconditions: Vec<PostconditionChange>,
  26→    /// Preconditions that changed between matching classes.
  27→    pub changed_preconditions: Vec<PreconditionChange>,
  28→    /// Invariant properties that held in the old spec but not the new.
  29→    pub lost_properties: Vec<String>,
  30→}
  31→
  32→/// A postcondition that changed between two versions of a spec class.
  33→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
  34→pub struct PostconditionChange {
  35→    /// Label of the class where the change occurred.
  36→    pub class_label: String,
  37→    /// The old postcondition.
  38→    pub old: Postcondition,
  39→    /// The new postcondition.
  40→    pub new: Postcondition,
  41→}
  42→
  43→/// A precondition change between two versions of a spec class.
  44→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
  45→pub struct PreconditionChange {
  46→    /// Label of the class where the change occurred.
  47→    pub class_label: String,
  48→    /// Preconditions that were removed (no longer hold).
  49→    pub removed: Vec<Precondition>,
  50→    /// Preconditions that were added (newly derived).
  51→    pub added: Vec<Precondition>,
  52→}
  53→
  54→impl SpecDiff {
  55→    /// Whether the diff is empty (specs are equivalent).
  56→    pub fn is_empty(&self) -> bool {
  57→        self.added_classes.is_empty()
  58→            && self.removed_classes.is_empty()
  59→            && self.changed_postconditions.is_empty()
  60→            && self.changed_preconditions.is_empty()
  61→            && self.lost_properties.is_empty()
  62→    }
  63→
  64→    /// Whether the diff contains regressions (removed classes, changed
  65→    /// postconditions, or lost properties).
  66→    pub fn has_regressions(&self) -> bool {
  67→        !self.removed_classes.is_empty()
  68→            || !self.changed_postconditions.is_empty()
  69→            || !self.lost_properties.is_empty()
  70→    }
  71→}
  72→
  73→/// Compare two function specs and produce a diff.
  74→///
  75→/// Classes are matched by their branch path. Classes with the same branch
  76→/// path are compared for precondition and postcondition changes. Classes
  77→/// that exist only in one spec are reported as added or removed.
  78→pub fn diff_specs(old: &FunctionSpec, new: &FunctionSpec) -> SpecDiff {
  79→    let mut added_classes = Vec::new();
  80→    let mut removed_classes = Vec::new();
  81→    let mut changed_postconditions = Vec::new();
  82→    let mut changed_preconditions = Vec::new();
  83→    let mut lost_properties = Vec::new();
  84→
  85→    // Collect nondeterministic fields from both specs (union).
  86→    let nondet_fields: Vec<&NondeterministicField> = old
  87→        .nondeterministic_fields
  88→        .iter()
  89→        .chain(new.nondeterministic_fields.iter())
  90→        .collect();
  91→
  92→    // Index old classes by branch path for matching.
  93→    let old_by_path: std::collections::HashMap<_, _> = old
  94→        .classes
  95→        .iter()
  96→        .map(|c| (&c.branch_path, c))
  97→        .collect();
  98→
  99→    let new_by_path: std::collections::HashMap<_, _> = new
 100→        .classes
 101→        .iter()
 102→        .map(|c| (&c.branch_path, c))
 103→        .collect();
 104→
 105→    // Find matched, added, and changed classes.
 106→    for new_class in &new.classes {
 107→        match old_by_path.get(&new_class.branch_path) {
 108→            Some(old_class) => {
 109→                // Matched by branch path — compare postconditions,
 110→                // excluding fields marked as nondeterministic.
 111→                if !postconditions_equal_ignoring_nondeterminism(
 112→                    &old_class.postcondition,
 113→                    &new_class.postcondition,
 114→                    &nondet_fields,
 115→                ) {
 116→                    changed_postconditions.push(PostconditionChange {
 117→                        class_label: old_class.label.clone(),
 118→                        old: old_class.postcondition.clone(),
 119→                        new: new_class.postcondition.clone(),
 120→                    });
 121→                }
 122→
 123→                // Compare preconditions using Vec-based set difference
 124→                // (Precondition contains serde_json::Value which doesn't impl Hash).
 125→                let removed: Vec<_> = old_class
 126→                    .preconditions
 127→                    .iter()
 128→                    .filter(|p| !new_class.preconditions.contains(p))
 129→                    .cloned()
 130→                    .collect();
 131→                let added: Vec<_> = new_class
 132→                    .preconditions
 133→                    .iter()
 134→                    .filter(|p| !old_class.preconditions.contains(p))
 135→                    .cloned()
 136→                    .collect();
 137→
 138→                if !removed.is_empty() || !added.is_empty() {
 139→                    changed_preconditions.push(PreconditionChange {
 140→                        class_label: old_class.label.clone(),
 141→                        removed,
 142→                        added,
 143→                    });
 144→                }
 145→            }
 146→            None => {
 147→                added_classes.push(new_class.clone());
 148→            }
 149→        }
 150→    }
 151→
 152→    // Find removed classes (in old but not in new).
 153→    for old_class in &old.classes {
 154→        if !new_by_path.contains_key(&old_class.branch_path) {
 155→            removed_classes.push(old_class.clone());
 156→        }
 157→    }
 158→
 159→    // Detect lost properties: invariant observations that no longer hold.
 160→    // An invariant is "all classes throw" or "all classes return".
 161→    let old_all_throw = !old.classes.is_empty()
 162→        && old
 163→            .classes
 164→            .iter()
 165→            .all(|c| matches!(c.postcondition, Postcondition::Throws { .. }));
 166→    let new_all_throw = !new.classes.is_empty()
 167→        && new
 168→            .classes
 169→            .iter()
 170→            .all(|c| matches!(c.postcondition, Postcondition::Throws { .. }));
 171→
 172→    if old_all_throw && !new_all_throw && !new.classes.is_empty() {
 173→        lost_properties.push("all paths throw an error".to_string());
 174→    }
 175→
 176→    let old_all_return = !old.classes.is_empty()
 177→        && old.classes.iter().all(|c| {
 178→            matches!(
 179→                c.postcondition,
 180→                Postcondition::Returns { .. } | Postcondition::ReturnsVoid
 181→            )
 182→        });
 183→    let new_all_return = !new.classes.is_empty()
 184→        && new.classes.iter().all(|c| {
 185→            matches!(
 186→                c.postcondition,
 187→                Postcondition::Returns { .. } | Postcondition::ReturnsVoid
 188→            )
 189→        });
 190→
 191→    if old_all_return && !new_all_return && !new.classes.is_empty() {
 192→        lost_properties.push("all paths return without error".to_string());
 193→    }
 194→
 195→    // Check if coverage dropped significantly.
 196→    if old.total_lines > 0 && new.total_lines > 0 {
 197→        let old_pct = old.lines_covered as f64 / old.total_lines as f64;
 198→        let new_pct = new.lines_covered as f64 / new.total_lines as f64;
 199→        if old_pct - new_pct > 0.1 {
 200→            lost_properties.push(format!(
 201→                "line coverage dropped from {:.0}% to {:.0}%",
 202→                old_pct * 100.0,
 203→                new_pct * 100.0,
 204→            ));
 205→        }
 206→    }
 207→
 208→    SpecDiff {
 209→        function_name: old.function_name.clone(),
 210→        added_classes,
 211→        removed_classes,
 212→        changed_postconditions,
 213→        changed_preconditions,
 214→        lost_properties,
 215→    }
 216→}
